import{_ as i,o as a,c as s,a2 as n}from"./chunks/framework.BfRM_mob.js";const k=JSON.parse('{"title":"Wiki-links","description":"","frontmatter":{},"headers":[],"relativePath":"guide/wiki-links.md","filePath":"guide/wiki-links.md","lastUpdated":1783734888000}'),t={name:"guide/wiki-links.md"};function o(r,e,l,h,d,p){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="wiki-links" tabindex="-1">Wiki-links <a class="header-anchor" href="#wiki-links" aria-label="Permalink to &quot;Wiki-links&quot;">​</a></h1><p>A wiki-link is an in-content reference — the <code>[[...]]</code> syntax you may know from wikis and Obsidian — and in wikimem it always points at <strong>one item</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># preferences.md</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## likes-the-sea</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">喜欢海边，提到过想去海边玩。[[</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">daily_life:beach-trip-plan</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># daily_life.md</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## beach-trip-plan</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">计划夏天去海边旅行，看日出。</span></span></code></pre></div><p><code>[[daily_life:beach-trip-plan]]</code> is an address with two parts: <strong>category</strong> (which file — <code>daily_life.md</code>) and <strong>item name</strong> (which <code>##</code> heading inside it). So the linked node is an <em>item</em>: a named, self-contained entry of a few sentences — <strong>not a word, and not a whole file</strong>.</p><p>When retrieval hits <code>likes-the-sea</code>, it mechanically expands its links one hop and injects the whole <code>beach-trip-plan</code> item alongside — no LLM call, no graph database. The &quot;graph&quot; is just text, and expansion is an exact-name lookup.</p><h2 id="why-links-when-there-s-already-search" tabindex="-1">Why links, when there&#39;s already search? <a class="header-anchor" href="#why-links-when-there-s-already-search" aria-label="Permalink to &quot;Why links, when there&#39;s already search?&quot;">​</a></h2><ul><li><strong>Search finds similar wording; links encode related meaning.</strong> A coffee preference and a morning routine may share no words — no keyword (often not even embedding) match connects them. A link written at memorization time does.</li><li><strong>One unit everywhere.</strong> The link target is the same unit retrieval ranks and the token budget trims: an item. Finer-grained than Obsidian&#39;s file-sized notes, so expanding a link never dumps an entire document into the prompt.</li><li><strong>Readable and writable by everyone.</strong> The extraction LLM emits links in the same single pass that writes the memory; you can add or fix them in any text editor; <code>git diff</code> shows them.</li><li><strong>Zero infrastructure, fail-soft.</strong> This replaces a graph database (the design it supersedes ran Neo4j for exactly this). A dangling link — target renamed or deleted — is tolerated and reported, never a crash.</li></ul><h2 id="who-writes-the-links" tabindex="-1">Who writes the links? <a class="header-anchor" href="#who-writes-the-links" aria-label="Permalink to &quot;Who writes the links?&quot;">​</a></h2><p>Anyone who can type two brackets:</p><ul><li><strong>The extraction LLM</strong>, in the same pass that writes the memory. The host passes the item names retrieval just surfaced as candidate targets, and the model connects new facts to them — see <a href="/wikimem/guide/host-integration.html">Host Integration</a>.</li><li><strong>You</strong>, in any text editor. Links are plain text in the content; the next <code>rebuild()</code> (or process restart) picks them up.</li></ul><h2 id="parsing-rules" tabindex="-1">Parsing rules <a class="header-anchor" href="#parsing-rules" aria-label="Permalink to &quot;Parsing rules&quot;">​</a></h2><p>Link parsing is deliberately liberal, because hand-edited files must never crash a read:</p><ul><li>The pattern is <code>[[category:name]]</code> — category is everything up to the <strong>first</strong> colon; neither part may contain <code>[</code>, <code>]</code>, a newline, or another colon.</li><li>Whitespace around either part is trimmed; malformed or empty links are silently ignored by the parser (not an error).</li><li>Item names are kept colon-free <strong>by construction</strong>: <code>sanitize_item_name</code> rejects <code>[[</code>, <code>]]</code>, <code>:</code>, <code>|</code>, <code>#</code> at write time, which keeps every link unambiguous and greppable.</li></ul><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> wikimem </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> parse_wiki_links</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">parse_wiki_links(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;… [[daily_life:beach-trip-plan]] and [[broken link …&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># [WikiLink(category=&#39;daily_life&#39;, name=&#39;beach-trip-plan&#39;)]</span></span></code></pre></div><h2 id="dangling-links" tabindex="-1">Dangling links <a class="header-anchor" href="#dangling-links" aria-label="Permalink to &quot;Dangling links&quot;">​</a></h2><p>Files are user-editable, so a link&#39;s target can be renamed or deleted at any time. wikimem treats that as normal life, not corruption:</p><ul><li>Expansion skips the missing target and keeps going.</li><li>The unresolved address is reported in <a href="/wikimem/reference/api.html#retrievalresult"><code>RetrievalResult.unresolved_links</code></a>, so a host (or the future <code>wikimem graph</code> CLI) can surface it for repair.</li></ul><h2 id="scope-one-hop-by-design" tabindex="-1">Scope: one hop, by design <a class="header-anchor" href="#scope-one-hop-by-design" aria-label="Permalink to &quot;Scope: one hop, by design&quot;">​</a></h2><p>Expansion is exactly one hop — hits pull in their direct link targets, and those targets do <strong>not</strong> pull in theirs; multi-hop chains surface hop-by-hop across turns as the conversation touches them. One hop keeps the injected context proportional to the hit count, the token cost predictable, and the behavior explainable (&quot;this item is here because that hit links to it&quot;). The same reasoning applies to the token budget&#39;s <a href="/wikimem/guide/retrieval.html#_4-token-budget">prefix-cut semantics</a>.</p>`,19)])])}const g=i(t,[["render",o]]);export{k as __pageData,g as default};
